// Helper function to get project images by key
export const getProjectImages = (projectKey: string): ProjectImage[] => {
  return projectImages[projectKey]?.images || [];
};

// Helper function to get first image (thumbnail) for a project
export const getProjectThumbnail = (projectKey: string): string => {
  const images = getProjectImages(projectKey);
  return images.length > 0 ? images[0].url : '';
};
